function PasswordGen() {
  const [len, setLen] = React.useState(16);
  const [upper, setUpper] = React.useState(true);
  const [lower, setLower] = React.useState(true);
  const [nums, setNums] = React.useState(true);
  const [sym, setSym] = React.useState(true);
  const [pwd, setPwd] = React.useState('');

  const generate = ()=>{
    let chars='';
    if(upper)chars+='ABCDEFGHIJKLMNOPQRSTUVWXYZ';
    if(lower)chars+='abcdefghijklmnopqrstuvwxyz';
    if(nums)chars+='0123456789';
    if(sym)chars+='!@#$%^&*()_+-=[]{}|;:,.<>?';
    if(!chars)return setPwd('');
    let p='';
    for(let i=0;i<len;i++)p+=chars[Math.floor(Math.random()*chars.length)];
    setPwd(p);
  };

  React.useEffect(()=>generate(),[]);

  const copy = ()=>{navigator.clipboard?.writeText(pwd);alert('Copied!');};

  const strength = (()=>{
    if(!pwd)return 0;
    let s=0;
    if(pwd.length>=12)s++;if(pwd.length>=16)s++;
    if(/[A-Z]/.test(pwd))s++;if(/[a-z]/.test(pwd))s++;if(/\d/.test(pwd))s++;if(/[^A-Za-z0-9]/.test(pwd))s++;
    return s;
  })();

  const strengthLabel = ['Very Weak','Weak','Fair','Good','Strong','Very Strong'];
  const strengthColor = ['#FF3B30','#FF3B30','#FF9500','#FFCC00','#34C759','#34C759'];

  return (
    <div style={{padding:16,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column'}}>
      <div style={{fontSize:18,fontWeight:700,marginBottom:12}}>Password Generator</div>
      <div style={{display:'flex',gap:8,marginBottom:12}}>
        <div style={{flex:1,padding:'10px 12px',background:'#f5f5f5',borderRadius:8,fontFamily:'monospace',fontSize:14,wordBreak:'break-all'}}>
          {pwd}
        </div>
        <button onClick={copy} style={{padding:'10px 14px',borderRadius:8,background:'#007AFF',color:'#fff',border:'none',cursor:'pointer'}}>Copy</button>
      </div>
      <div style={{marginBottom:8}}>
        <div style={{height:6,background:'#eee',borderRadius:3}}>
          <div style={{width:`${(strength/6)*100}%`,height:'100%',background:strengthColor[strength],borderRadius:3,transition:'all 0.3s'}}/>
        </div>
        <div style={{fontSize:12,color:'#888',marginTop:4}}>{strengthLabel[strength]}</div>
      </div>
      <div style={{marginBottom:8}}>
        <div style={{fontSize:12,color:'#888',marginBottom:4}}>Length: {len}</div>
        <input type="range" min="8" max="64" value={len} onChange={e=>setLen(Number(e.target.value))}
          style={{width:'100%'}}/>
      </div>
      <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:8,marginBottom:12}}>
        <label style={{display:'flex',alignItems:'center',gap:6,fontSize:13,cursor:'pointer'}}>
          <input type="checkbox" checked={upper} onChange={e=>setUpper(e.target.checked)}/> ABC
        </label>
        <label style={{display:'flex',alignItems:'center',gap:6,fontSize:13,cursor:'pointer'}}>
          <input type="checkbox" checked={lower} onChange={e=>setLower(e.target.checked)}/> abc
        </label>
        <label style={{display:'flex',alignItems:'center',gap:6,fontSize:13,cursor:'pointer'}}>
          <input type="checkbox" checked={nums} onChange={e=>setNums(e.target.checked)}/> 123
        </label>
        <label style={{display:'flex',alignItems:'center',gap:6,fontSize:13,cursor:'pointer'}}>
          <input type="checkbox" checked={sym} onChange={e=>setSym(e.target.checked)}/> !@#
        </label>
      </div>
      <button onClick={generate} style={{padding:'10px',borderRadius:8,background:'#34C759',color:'#fff',border:'none',cursor:'pointer',fontSize:14,fontWeight:600}}>
        Generate New
      </button>
    </div>
  );
}
render(<PasswordGen/>);
